/**
 * Returns the image binary with optional width/height for resized versions
 * @summary Retrieve processed image binary
 */
export const getFindImageUrl = (id: string, params?: FindImageParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/images/find/${id}?${stringifiedParams}`
    : `/api/images/find/${id}`;
};

export const findImage = async (
  id: string,
  params?: FindImageParams,
  options?: RequestInit,
): Promise<Blob> => {
  return customFetch<Blob>(getFindImageUrl(id, params), {
    ...options,
    method: "GET",
  });
};

